<?php namespace App\Providers; use Illuminate\Support\ServiceProvider; use Illuminate\Support\Facades\RateLimiter; use Illuminate\Cache\RateLimiting\Limit; use Illuminate\Http\Request; use Illuminate\Support\Facades\Route; class SecurityServiceProvider extends ServiceProvider { public function register(): void { $this->app->singleton('security', function ($app) { return new \App\Services\SecurityService(); }); } public function boot(): void { $this->configureRateLimiting(); $this->configureSecurityHeaders(); } protected function configureRateLimiting(): void { RateLimiter::for('api', function (Request $request) { return Limit::perMinute(60)->by($request->user()?->id ?: $request->ip()); }); } protected function configureSecurityHeaders(): void { $this->app['router']->middlewareGroup('security', [ \Illuminate\Http\Middleware\HandleCors::class, \Illuminate\Http\Middleware\TrustProxies::class, ]); } }